// This program calculates the factorial of a non-negative integer x
// The variable x is set to 7 for demonstration purposes

// Variable declaration and initialization
let x = 7; // Assigning a concrete value to x

// Function to compute the factorial of x
function computeFactorial(w) {
    let result = 1;
    for (let i = 1; i <= w; i++) {
        result *= i;
    }
    return result;
}

